import json
import sys
import traceback
import requests
import time

CONNECTOR_PATH = "/run/connector.json"


def load_context():
    with open(CONNECTOR_PATH, "r", encoding="utf-8") as f:
        data = json.load(f)
    auth = data.get("auth") or {}
    cfg = data.get("configuration") or {}
    return auth, cfg


def fail(message, **details):
    out = {"status": "error", "message": message}
    if details:
        out.update(details)
    print(json.dumps(out))
    sys.exit(1)


def quote_jql_string(value):
    if value is None:
        return '""'
    # Escape backslashes and quotes in the value for safe JQL
    s = str(value).replace("\\", "\\\\").replace('"', '\\"')
    return f'"{s}"'


def build_jql(project_key, assignee_account_id):
    # For Jira Cloud, using accountId for user fields is required and should not be quoted.
    # Project keys are quoted and escaped for safety.
    return f'project = {quote_jql_string(project_key)} AND assignee = {assignee_account_id}'


def parse_positive_int(value, default):
    try:
        n = int(value)
    except Exception:
        return default
    return max(0, n)


def do_request_with_retries(method, url, headers, params, auth, timeout=30, max_attempts=3):
    attempt = 0
    while attempt < max_attempts:
        try:
            resp = requests.request(method, url, headers=headers, params=params, auth=auth, timeout=timeout)
        except Exception:
            attempt += 1
            if attempt >= max_attempts:
                raise
            time.sleep(min(2 ** attempt, 8))
            continue
        if resp.status_code in (429, 502, 503, 504):
            attempt += 1
            if attempt >= max_attempts:
                return resp
            retry_after = resp.headers.get("Retry-After")
            wait = None
            if retry_after:
                try:
                    wait = int(retry_after)
                except Exception:
                    wait = None
            if wait is None:
                wait = min(2 ** attempt, 8)
            time.sleep(wait)
            continue
        return resp
    return resp


def main():
    try:
        auth, cfg = load_context()

        base_url = (auth.get("baseUrl") or "").strip()
        email = (auth.get("email") or "").strip()
        api_token = (auth.get("apiToken") or "").strip()

        project_key = (cfg.get("projectKey") or "").strip()
        assignee_account_id = (cfg.get("assigneeAccountId") or "").strip()
        # Normalize if user accidentally wrapped it in quotes
        if assignee_account_id.startswith('"') and assignee_account_id.endswith('"'):
            assignee_account_id = assignee_account_id[1:-1].strip()

        max_issues = parse_positive_int(cfg.get("maxIssues", 50), 50)
        dry_run = bool(cfg.get("dryRun", False))

        # Validate inputs
        missing = []
        if not base_url:
            missing.append("auth.baseUrl")
        if not email:
            missing.append("auth.email")
        if not api_token:
            missing.append("auth.apiToken")
        if not project_key:
            missing.append("configuration.projectKey")
        if not assignee_account_id:
            missing.append("configuration.assigneeAccountId")
        if missing:
            fail("Missing required inputs", missing=missing)

        base_url = base_url.rstrip("/")
        if not (base_url.startswith("http://") or base_url.startswith("https://")):
            fail("Invalid baseUrl: must start with http:// or https://", baseUrl=base_url)

        # Build JQL
        jql = build_jql(project_key, assignee_account_id)

        # Prepare request details
        endpoint = f"{base_url}/rest/api/3/search"
        headers = {
            "Accept": "application/json",
            "User-Agent": "ai-connector-jira/1.0"
        }

        if dry_run:
            planned_batches = []
            remaining = max_issues
            start_at = 0
            while remaining > 0:
                batch_size = remaining if remaining < 100 else 100
                planned_batches.append({
                    "method": "GET",
                    "url": endpoint,
                    "params": {
                        "jql": jql,
                        "startAt": start_at,
                        "maxResults": batch_size,
                        "fields": "summary,status,assignee,project"
                    }
                })
                remaining -= batch_size
                start_at += batch_size
            print(json.dumps({
                "status": "dry_run",
                "message": "Validated configuration. No request sent.",
                "jql": jql,
                "batchesPlanned": planned_batches
            }))
            return

        issues = []
        total = None
        remaining = max_issues
        start_at = 0

        while remaining > 0:
            batch_size = remaining if remaining < 100 else 100
            params = {
                "jql": jql,
                "startAt": start_at,
                "maxResults": batch_size,
                "fields": "summary,status,assignee,project"
            }
            try:
                resp = do_request_with_retries(
                    method="GET",
                    url=endpoint,
                    headers=headers,
                    params=params,
                    auth=(email, api_token),
                    timeout=30,
                    max_attempts=3
                )
            except Exception as e:
                fail("Network or request error when calling Jira", exception_type=type(e).__name__, detail=str(e))

            if resp.status_code >= 400:
                try:
                    err_body = resp.json()
                except Exception:
                    err_body = {"text": resp.text}
                fail("Jira API returned an error", status_code=resp.status_code, response=err_body)

            data = resp.json()
            if total is None:
                total = data.get("total")

            for it in data.get("issues", []):
                fields = it.get("fields") or {}
                status = fields.get("status") or {}
                assignee = fields.get("assignee") or {}
                project = fields.get("project") or {}
                issues.append({
                    "id": it.get("id"),
                    "key": it.get("key"),
                    "self": it.get("self"),
                    "summary": fields.get("summary"),
                    "status": status.get("name"),
                    "assigneeDisplayName": assignee.get("displayName"),
                    "assigneeAccountId": assignee.get("accountId"),
                    "projectKey": project.get("key"),
                    "projectName": project.get("name")
                })
                if len(issues) >= max_issues:
                    break

            fetched = len(data.get("issues", []))
            if fetched == 0 or len(issues) >= max_issues:
                break

            remaining = max_issues - len(issues)
            start_at += fetched

        print(json.dumps({
            "status": "ok",
            "jql": jql,
            "requestedMax": max_issues,
            "returned": len(issues),
            "total": total,
            "issues": issues
        }))

    except SystemExit:
        raise
    except Exception as e:
        print(json.dumps({
            "status": "error",
            "message": "Unhandled exception",
            "exception_type": type(e).__name__,
            "error": str(e),
            "traceback": traceback.format_exc()
        }))
        sys.exit(1)


if __name__ == "__main__":
    main()
